var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"음? 넌 뭐야?","JPN":"うん？　お前は誰だ？","ENG":"Mm? Who are you?","TWN":"嗯？你是誰？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 저번에 바텐더 면접을 보기로 연락 드렸던 니콜 프라이머라고 합니다.","JPN":"はじめまして。バーテンダーの面接を受けに来た、ニコル・プライマーです。","ENG":"Nice to meet you. My name is Nicole Primer. I'm here for my bartender interview.","TWN":"你好，初次見面，我叫妮可·布萊伊莫，之前有打來說要應徵調酒師。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"바텐더 면접? 우리가 그런 걸 봤었나?","JPN":"バーテンダーの面接？　そんなのあったっけ？","ENG":"Bartender interview? Do we even do that sort of thing?","TWN":"應徵調酒師？有這回事嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"잠깐, 새로운 바텐더라면 보스 추천으로 온다던 프로 아냐?","JPN":"まて、新しいバーテンダーならボスの推薦で来るといったプロじゃないか？","ENG":"Wait, is she the new bartender? The pro, who came highly recommended by the Boss?","TWN":"等等，新來的調酒師，那不就是之前老大推薦的專家？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"아, 그 사람?","JPN":"ああ、例の？","ENG":"Oh, is she?","TWN":"喔～那個人喔？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"하지만 저렇게 밝은 인상일 줄은 몰랐는데……?","JPN":"だがこんな明るい印象だとは思わなかったが……","ENG":"But I didn't think she'd be such a cheerful sort...","TWN":"沒想到形象這麼……小清新？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"인상이 무슨 상관이야. 중요한 건 실력이지.","JPN":"印象なんて関係ないだろ。大事なのは実力だ。","ENG":"Who cares? What matters is her skills.","TWN":"人不可貌相啦，重點是實力！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(우와, 제가 사전에 공부했던 바텐더와는 조금 다른 분위기…)","JPN":"(わあ、私が以前勉強したバーテンダーとはちょっと違う雰囲気……)","ENG":"(Whoa, they're a bit different from the bartenders I imagined...)","TWN":"(哇，怎麼跟我在書上看到的調酒師感覺不太一樣…)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(역시 책으로 배운 것과 현실은 조금 거리가 있네요.)","JPN":"(やっぱり本で学んだことと現実は少し違うみたいですね。)","ENG":"(I guess there is a gap between knowledge and reality.)","TWN":"(書本的知識和現實果然是有點落差的。)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"당신 소문은 들었어. 조직에 들어온 지 얼마 안 돼서 보스에게 인정받았다지?","JPN":"あんたの噂は聞いたぜ。\\n組織に入ってすぐにボスから実力を認められたそうだな。","ENG":"I've heard things about you. You haven't been with us long, but you already managed to impress the Boss. Is that right?","TWN":"久仰大名，聽說你進到組織後沒多久，就很受到老大的重用是吧？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"蛤？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(소문? 조직? 보스?)","JPN":"(噂？　組織？　ボス？)","ENG":"(What things about me? With whom? Who's the Boss?)","TWN":"(什麼大名？組織？老大？)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(이 사람들 설마, 제가 구마회에서 왔다는 사실을 알고 있는 걸까요?)","JPN":"(この人たちはまさか、私が祓魔会から来た事実を知っているのでしょうか？)","ENG":"(Oh no, do they know I'm from the Exorcism Council?)","TWN":"(這些人該不會知道我是從驅魔會來的吧？)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(자, 침착해요. 퇴마사가 아닌 바텐더 지망생으로서의 완벽한 연기를 보여주는 거예요.)","JPN":"(お、落ち着きましょう。エクソシストではなく、バーテンダーの卵としての完璧な演技を見せるのです。)","ENG":"(Calm down, Nicole. Right now, you're not an exorcist but a bartender. Act like it.)","TWN":"(先冷靜點，我現在是調酒師，不是驅魔師，我要展現出專業的態度。)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"<color=#ffd34c>블랜딩</color> 실력이 꽤 좋다고 들었는데. 온 김에 우리 애들한테 시범 좀 보여 줘.","JPN":"<color=#ffd34c>ブレンド</color>の腕前がなかなかだと聞いたが、せっかくだし手本を見せてくれ。","ENG":"I've heard you're pretty good at <color=#ffd34c>blending</color>. Why don't you show us what you can do while you're here?","TWN":"我聽說你很會<color=#ffd34c>調製</color>，機會難得，不如你就示範一下給我們看吧！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? …네! 어떤 걸 만들어 볼까요?","JPN":"え？　……はい！　いいですよ、何を作りましょうか？","ENG":"Huh? ... Sure! What do you want me to make?","TWN":"什？ …好！要調什麼呢？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"큭큭, 우리가 원하는 거야 뻔하지. 아주 독한 거로 만들어 달라고.","JPN":"ククク、俺らが求めるのは決まってる。一番強いやつを頼む。","ENG":"Hah hah. You know what we want. The strongest one you can make.","TWN":"呵呵，當然是那個囉～幫我們弄個最烈的來試試看！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음, 좋아요! 이런 날씨엔 스피리츠가 제격이죠!","JPN":"うーん、わかりました！\\n今日みたいな天気にはスピリッツがおすすめです！","ENG":"Mm... Okay! A high-proof spirit is perfect for this weather!","TWN":"嗯嗯，好喔！這種天氣正好適合來點烈酒！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 여기 혹시 얼음 없나요?","JPN":"あ、ここに氷はありませんか？","ENG":"Oh, do you have ice?","TWN":"那個，請問有冰塊嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"자! 이렇게 해서, 프로즌 마가리타 완성이에요!","JPN":"さあ！　こうすれば、フローズンマルガリータの出来上がり！","ENG":"There you go! I've got you a frozen margarita!","TWN":"鏘鏘～霜凍瑪格麗特完成囉！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"평범하게 얼음을 갈고 데킬라를 섞었을 뿐이잖아?","JPN":"普通に砕いた氷にテキーラを混ぜただけじゃないか？","ENG":"She just mixed ground ice with tequila.","TWN":"這不就是普通的碎冰加烈酒嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"딱히 치명적인 재료가 들어가진 않았다고.","JPN":"特に致命的な材料は入ってないぞ。","ENG":"She didn't put anything deadly.","TWN":"又沒有加入最重要的材料！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"진정해. 우리가 만드는 것들이 다 그런 거지.","JPN":"落ち着け。俺らが作るものってそんなもんだろ。","ENG":"Settle down. This is what we do;","TWN":"你先別激動，我們調的不都是這樣嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"치명적이면서도, 겉으로 티가 나지 않을수록 좋은 거야.","JPN":"致命的だが、見た目ではわからないものほどいいんだよ。","ENG":"making deadly things that look so innocent.","TWN":"雖然致命，但是肉眼又看不出來才是最好的。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"내 눈엔 평범한 술로 보이는데?","JPN":"俺の目には普通の酒にしか見えないが。","ENG":"To me, this just looks like an ordinary margarita.","TWN":"但我看起來它就是一杯普通的酒欸？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"후훗, 맛이라면 자신 있어요! 드셔 보시면 분명 생각이 바뀔 거예요!","JPN":"ふふっ、味なら自信があります！\\n飲んでみたらきっと印象が変わりますよ！","ENG":"Heh heh. I assure you it's delicious. It'll change your mind if you drink it!","TWN":"呵呵，味道我可是很有信心的！包你喝下去一定會改變想法！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"…우웃! 아, 알겠어! 알았으니까, 그 위험한 거 갑자기 들이밀지 말라고!","JPN":"……わ、わかった！　わかったからその危険なモノを突きつけるな！","ENG":"Wah! O-okay! Keep that dangerous thing away from my face!","TWN":"…這樣嗎！那好吧，就姑且信你一次吧！這東西這麼危險，不要拿得靠我這麼近啦！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"윽, 위험한 거라니 너무하세요.","JPN":"えっ、危険なモノだなんてひどいですよ。","ENG":"What? No, it's not dangerous.","TWN":"嗚，竟然說我這杯很危險，過分！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"하하, 진정해. 아가씨.","JPN":"ハハ、落ち着けお嬢ちゃん。","ENG":"Hah hah. Calm down, lady.","TWN":"哈哈，小妞你別生氣。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"테이스팅이 중요하긴 해도 우리가 만든 걸 직접 마실 필요는 없다고.","JPN":"テイスティングは大事だが、俺らが直接飲む必要はないだろ。","ENG":"Tasting it is important, sure, but we don't have to do it ourselves.","TWN":"試飲是很重要沒錯，但我們不需要自己來。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아… 하긴 술은 가게의 재산이니까요. 직원이 마시는 건 좀 그렇죠?","JPN":"あ……確かにお酒はお店の財産ですもんね。\\n店員が飲むのはちょっとまずいですかね？","ENG":"Ah, I get it. The liquor is the shop's asset, too. It shouldn't be wasted on the employees, right?","TWN":"喔…畢竟酒也要算在開店的成本裡，員工自己喝掉有點那個對吧？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 가게에 손님이 안 보이는데, 어떤 분에게 드리면 좋을까요?","JPN":"でもお店にお客様は見えないし、どなたに渡せばいいんですか？","ENG":"But I don't see any customers here. To whom should I serve this?","TWN":"不過怎麼都沒看到客人？那這杯要給誰才好？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"큭큭, 손님이라면 걱정 마. 마침 딱 좋은 시험대상이 있거든.","JPN":"ククク、飲ませる客なら心配するな。ちょうどいい実験体がいるぜ。","ENG":"Hah hah, don't worry about it. I've got just the right test subject for you.","TWN":"呵呵，放心吧，我有個很適合的人選！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"어이, 창고에 대기 중이신 손님 한 분 모셔와.","JPN":"おい、倉庫で待機中の客を一人連れてこい。","ENG":"Hey, go bring one of the customers waiting in the warehouse.","TWN":"喂！把在倉庫裡等的客人帶過來！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_NULL","text":{"KOREA":"히익…! 사, 살려주십쇼, 선생님들! 저는 집에 가족이 있다고요!","JPN":"ひいっ……！　ど、どうか命だけは！　私には家族がいるんです！","ENG":"Heek! P-please don't kill me, sirs! I've got family to feed!","TWN":"嗚嗚…！放過我吧，各位大哥！我家裡還有一家老小呢！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"이 손님은 우리 영업장에서 사기를 치다 걸린 채무자야. 부담 갖지 말고 대접해 줘.","JPN":"この客はうちの縄張りで詐欺をしてたのがバレた債務者だ。\\nしっかりおもてなししてやれ。","ENG":"This customer here owes us a lot of money; we caught him cheating in one of our venues. Serve him as best as you can.","TWN":"這位客人在店裡耍詐被抓到，所以欠我們錢，你就儘管放心拿他做實驗吧！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"채무자 씨로군요! 알겠습니다!","JPN":"債務者さんなんですね！　了解しました！","ENG":"Owes money, huh? Got it!","TWN":"原來是債務人喔！好的，沒問題！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(이 손님은 팔을 묶고 계시네요.)","JPN":"(このお客様は腕が縛られていますね。)","ENG":"(This customer is bound with a rope around his arms.)","TWN":"(但他的手被綁起來欸？)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(아! 책에서 봤어요. 수준 높은 소믈리에들은 일부러 눈을 가리고 테이스팅을 하기도 한다던데.)","JPN":"(あ！　そういえば本で見ました！\\n上級者のソムリエはわざと目隠ししてテイスティングをするらしいですね。)","ENG":"(Ah, I read about this in the book! Some high-class sommeliers cover their eyes for tasting.)","TWN":"(對吼！我在書上有看過，有些專業的侍酒師，試飲時會故意把眼睛遮起來。)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(이 분은 아무래도 한층 더 고차원적인 미식가인가 봐요.)","JPN":"(この方はどうやらかなりの美食家さんのようです。)","ENG":"(Perhaps this person wants a more advanced level of tasting.)","TWN":"(我看他可能是米其林等級的美食家吧！)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님! 제가 만든 프로즌 마가리타 한잔 어떠신가요?","JPN":"お客様！　私が作ったフローズンマルガリータはいかがでしょうか？","ENG":"Sir, would you like to taste this frozen margarita I've made?","TWN":"這位客人！要來一杯我特調的霜凍瑪格麗特嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_NULL","text":{"KOREA":"그, 그거 저리 치워! 제발 살려줘!","JPN":"た、頼む！　飲みたくないんだ！　どうか助けてくれ！","ENG":"P-put that thing away! Please, help!","TWN":"唔…拿走開！拜託你饒我一命吧！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으으, 부디 한 잔만 마셔 주세요. 전 이분들한테 잘 보여서 꼭 여기 취업해야 한단 말이에요.","JPN":"うう、どうか一杯だけでもお願いします。\\nここで働くためにも、絶対この面接に受かる必要があるんです。","ENG":"Oh, come on. Please drink it. I must impress these people to get a job here.","TWN":"呃…我拜託你就喝一杯吧！我要在他們面前有好的表現，才能在這裡上班。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_NULL","text":{"KOREA":"크윽…! 고작 그런 이유로 나에게 이걸 먹인다고? 이 피도 눈물도 없는 여자 같으니!","JPN":"くっ……！　そんな理由で俺にこんなモノを飲ませるのか？\\nこの血も涙もない女め！","ENG":"Gah! You want to feed me this because you want a job? You heartless witch!","TWN":"嗚嗚…！竟然只是因為那種理由，就要我把這個東西喝下去？你這沒血沒淚的女人！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?! 그렇게까지 심한 말씀을…!","JPN":"ええっ！？　そこまで言わなくても……","ENG":"Excuse me? You don't have to call me names!","TWN":"什麼？！話有必要說得這麼難聽嗎…！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"질질 끌 필요 없어. 깔대기를 꽂아서라도 억지로 먹여.","JPN":"ダラダラと時間の無駄だ。漏斗を使ってでも飲ませろ。","ENG":"What's the holdup? Pour it into his mouth if you have to.","TWN":"跟他廢話那麼多幹嘛！乾脆拿漏斗插在他嘴裡，直接灌下去啦！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에에에?!","JPN":"ええええっ！？","ENG":"Excuse me?","TWN":"什麼？！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(바텐더는 손님에게 술을 억지로 먹이는 건가요?)","JPN":"(バーテンダーがお客様に無理やりお酒を飲ませていいのでしょうか？)","ENG":"(Do bartenders have to force-feed drinks to their customers?)","TWN":"(調酒師可以這樣強灌客人喝酒嗎？)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(우선 손님이랑 대화로 친해져야 한다고 배웠는데?)","JPN":"(まずはお客様とトークで仲良くなる必要があると学んだのに？)","ENG":"(I thought I first needed to chat and build a rapport with them.)","TWN":"(可是書上說，要藉由對話和客人拉近距離欸？)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(책에서 본 거랑 달라도 너무 다른데요?!)","JPN":"(本で勉強した内容とあまりにも違いすぎますが！？)","ENG":"(This is completely different from what I read in books!)","TWN":"(怎麼跟我在書上看到的差這麼多？！)"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_NULL","text":{"KOREA":"으, 우우웁. 사, 살려줘!","JPN":"うっ、うんぐぐ！　た、助けてくれ！","ENG":"M-mpffftt! H-help!","TWN":"嗚嗚嗚…拜託饒命！"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저기… 꼭 그렇게 억지로 먹여야 하는 건가요? 바텐더로서 그런 짓을 해도 괜찮은 건가요?","JPN":"あの……そこまでする必要があるんですか？\\nバーテンダーとして、そんなことをしていいのでしょうか？","ENG":"Hey, erm, do we really have to force-feed him? Is that even ethical?","TWN":"那個…有必要這樣強灌嗎？調酒師可以做這種事嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"무슨 소릴 하는 거야? 독을 만든다는 녀석이 사람한테 직접 먹여 본 적은 없다고?","JPN":"何言ってんだ？\\n毒を作るやつが人に直接飲ませたことねえのか？","ENG":"What are you talking about? You make poison. Haven't you tested it on people before?","TWN":"你在說什麼？身為一個製毒的人，你沒有親自餵毒的經驗嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOSTAGE_NPC_POSIONRAT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그, 그게… 칵테일은 책으로만 배워서 직접 손님을 상대해 본 적은…","JPN":"そ、それが……カクテル作りは本で勉強したもので、\\nお客様相手に出したことは……","ENG":"W-well... I've only learned how to make cocktails from books. I've never handled customers before...","TWN":"那個…我的調酒技術是看書學的，沒有實際應對客人的…"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 잠깐. 독이라고요?","JPN":"ん？　待ってください、毒ですって？","ENG":"Wait, what? Poison?","TWN":"等等，你說製毒？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"잠깐. 칵테일이라고?","JPN":"ちょっと待て、カクテルだと？","ENG":"Wait, what? Cocktails?","TWN":"等等，你說調酒？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"어이, 이 녀석. 다 마시게 했는데도 아직 멀쩡한데?","JPN":"おい。こいつ、飲み干したのにまだ平気だぞ？","ENG":"Hey, look at him. He drank the entire thing, and he's still alive.","TWN":"喂，他把酒全喝光啦，但沒事欸？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_NULL","text":{"KOREA":"으으……. 딸꾹.","JPN":"あうぅ……ひっく。","ENG":"Aww... *Hiccups!*","TWN":"唔唔……咕嚕。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗?! 설마 제가 만든 게 독이라고 생각하신 건가요?","JPN":"あっ！？　まさか私が作ったのが毒だと思ったんですか？","ENG":"Oh no, did you think I made poison?","TWN":"嗯？！你以為我調的是毒品嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"그럼 너 진짜로 평범한 칵테일을 만든 거였나?!","JPN":"もしかしてお前、本当に普通のカクテルを作ったのか！？","ENG":"Then, what? Did you really make an ordinary cocktail?","TWN":"所以你調的真的就只是一杯普通的雞尾酒？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"대체 일반인이 여길 어떻게 들어온 거지?","JPN":"一般人がどうやってここに入ってきたんだ？","ENG":"You're not one of us. How did you get in here?","TWN":"外人是怎麼進來的？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그, 그건… 바텐더 직원을 구하지 않냐고 했더니 열어주시던데요?","JPN":"え、えっと……バーテンダーを募集していないか聞いたら、扉を開けてくれましたよ？","ENG":"I-I asked your doorkeeper if you were hiring bartenders, and he let me in.","TWN":"那個…我就說我要應徵調酒師，他就放我進來啦？"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"……유감이지만, 우린 술 만드는 바텐더를 모집한 적 없어.","JPN":"……残念だが、俺らは酒を作るバーテンダーを募集したんじゃない。","ENG":"Sorry, but we're not hiring bartenders. Not real ones, anyway.","TWN":"……不好意思，我們沒有要應徵調酒師。"},"stage":{"bg":"FACILITY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"아무래도 문지기가 엉뚱한 사람을 들여보낸 모양이군.","JPN":"どうやら門番がよそ者を通したみたいだな。","ENG":"The doorkeeper must have mistaken you for someone else.","TWN":"看門的把不長眼的人放進來啦？！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"어이, 문 잠가.","JPN":"おい、ドアを閉めろ。","ENG":"Hey, lock the door.","TWN":"喂！把門關上！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아앗?! 갑자기 이게 무슨 상황이죠?","JPN":"ええっ！？　急にどうしたんですか？","ENG":"Huh? What are you doing?","TWN":"哇咧咧？！現在是什麼情況？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"우리 <color=#ffd34c>포이즌랫</color>의 제조실에 발을 들인 외부인을 그냥 보내줄 순 없지.","JPN":"俺ら<color=#ffd34c>ポイズンラット</color>の製造室にのうのうと足を踏み入れたよそ者を、そのまま帰らせるわけにはいかない。","ENG":"Any outsider who enters the <color=#ffd34c>Poison Rats</color>' workshop has to pay a price.","TWN":"被你發現我們<color=#ffd34c>毒鼠幫</color>的製毒工廠，怎麼可以讓你活著離開呢？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……포이즌랫? 그게…… 뭔가요?","JPN":"……ポイズンラット？　それは……なんですか？","ENG":"Poison Rats? What's that?","TWN":"……毒鼠幫？那是……什麼？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"나 참, 동네 꼬마들도 아는 우리를 누군지 모른다고? 이 도시 출신이 아니군.","JPN":"まったく、そこら辺のガキも知ってる俺らのことを知らないのか？\\nこの都市の出身じゃないようだな。","ENG":"Geez, even a three-year-old knows about us. You're not from this city, are you?","TWN":"拜託！連附近小鬼都聞之喪膽的毒鼠幫你不認識？我看你是外地來的吧！"},"stage":{"bg":"FACILITY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"오히려 잘됐어. 연고가 없는 외지인이라면 여기서 사라져도 아무도 모르겠지.","JPN":"むしろよかったな。ゆかりのないよそ者なら急に消えても誰も気づかないだろ。","ENG":"All the better. No one will look for you even if you disappear.","TWN":"這樣也好！在這裡無親無故的外地人，就算消失也不會有人發現的。"},"stage":{"bg":"FACILITY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다, 다가오지 마세요! 후회해도 전 몰라요!","JPN":"ち、近づかないでください！　後悔しても知りませんよ！","ENG":"S-stay away! Or else!","TWN":"你…你們別過來喔！要是受傷我可不負責喔！"},"stage":{"bg":"FACILITY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};